/* 相性スコア: 濃さ逆+1 / 温度同+1 / 甘辛逆+1 / 入手性逆+1 */
function pairScore(a, b) {
  const A = TYPES[a].axes, B = TYPES[b].axes;
  let s = 0;
  if (A[0] !== B[0]) s++;
  if (A[1] === B[1]) s++;
  if (A[2] !== B[2]) s++;
  if (A[3] !== B[3]) s++;
  return s;
}

